import { useMemo, useState } from 'react'

//context
import GroupsContext from './GroupsContext'

//hooks
import { useScores } from '../hooks/useScores'

//standings
import { computeKnockoutSchedule, computeStandings } from '../standings'

const GroupsProvider = ({ children }) => {
	const groupStagePos = 0
	const knockOutStagePos = 1
	const finalFormPos = 2
	const [knockOutStage, setKnockOutStage] = useState([])
	const [stage, setStage] = useState(groupStagePos)
	const [loading, scores] = useScores()

	const { standings, groupFinished, groupStageComplete } = useMemo(
		() => computeStandings(scores),
		[scores],
	)
	const knockoutSchedule = useMemo(
		() => computeKnockoutSchedule(scores),
		[scores],
	)

	return (
		<GroupsContext.Provider
			value={{
				loading,
				scores,
				standings,
				groupFinished,
				groupStageComplete,
				knockoutSchedule,
				knockOutStage,
				setKnockOutStage,
				groupStagePos,
				knockOutStagePos,
				finalFormPos,
				stage,
				setStage,
			}}>
			{children}
		</GroupsContext.Provider>
	)
}

export default GroupsProvider
