import { useContext, useState, useEffect } from 'react'
import { useForm } from 'react-hook-form'

// constants
import {
	epigraph,
	isPlayed,
	urlFlags,
	sessionStorageKey,
} from '../../Constants'

// teams
import { teamsByGroup } from '../../teams/TeamsByGroup'

// knockout
import { buildRoundOf32 } from '../../knockout/bracket2026'
import { rankGroupTeams } from '../../standings'

// context
import GroupsContext from '../../context/GroupsContext'

// components
import MatchesByGroup from './MatchesByGroup'
import StandingByGroup from './StandingByGroup'
import ThirdPlaceTable from './ThirdPlaceTable'

const GroupStage = () => {
	const { groupFinished, scores, setKnockOutStage, setStage, knockOutStagePos } =
		useContext(GroupsContext)

	const [standings, setStandings] = useState({})
	const [showStandings, setShowStandings] = useState(false)

	// ✅ A–L forms (Mundial 2026)
	const {
		register: registerA,
		formState: { errors: errorsA },
		handleSubmit: handleSubmitA,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerB,
		formState: { errors: errorsB },
		handleSubmit: handleSubmitB,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerC,
		formState: { errors: errorsC },
		handleSubmit: handleSubmitC,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerD,
		formState: { errors: errorsD },
		handleSubmit: handleSubmitD,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerE,
		formState: { errors: errorsE },
		handleSubmit: handleSubmitE,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerF,
		formState: { errors: errorsF },
		handleSubmit: handleSubmitF,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerG,
		formState: { errors: errorsG },
		handleSubmit: handleSubmitG,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerH,
		formState: { errors: errorsH },
		handleSubmit: handleSubmitH,
	} = useForm({ mode: 'onSubmit' })

	const {
		register: registerI,
		formState: { errors: errorsI },
		handleSubmit: handleSubmitI,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerJ,
		formState: { errors: errorsJ },
		handleSubmit: handleSubmitJ,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerK,
		formState: { errors: errorsK },
		handleSubmit: handleSubmitK,
	} = useForm({ mode: 'onSubmit' })
	const {
		register: registerL,
		formState: { errors: errorsL },
		handleSubmit: handleSubmitL,
	} = useForm({ mode: 'onSubmit' })

	const pointsWinner = 3
	const pointsTie = 1
	const pointsLoser = 0

	// ⚠️ mantiene tu enfoque actual (var)
	// ✅ fix: siempre reiniciar por cada score para que no “arrastre”
	// ✅ fix: si match no está finished, igual setea defaults seguros
	var matchResults = []

	const getMatchResults = (
		home,
		away,
		goalsHome,
		goalsAway,
		pointsHome,
		pointsAway,
		drawnHome,
		drawnAway,
		winner,
		loser,
	) => {
		pointsHome = pointsTie
		pointsAway = pointsTie
		drawnHome = home
		drawnAway = away

		if (goalsHome > goalsAway) {
			pointsHome = pointsWinner
			pointsAway = pointsLoser
			winner = home
			loser = away
			drawnHome = ''
			drawnAway = ''
		} else if (goalsAway > goalsHome) {
			pointsAway = pointsWinner
			pointsHome = pointsLoser
			winner = away
			loser = home
			drawnHome = ''
			drawnAway = ''
		}

		return [pointsHome, pointsAway, drawnHome, drawnAway, winner, loser]
	}

	const getMatches = (scoresApi) => {
		var matches = []
		var match = {}
		var matchNumber = ''
		var groupId = ''
		var home = ''
		var goalsHome = 0
		var goalsAway = 0
		var away = ''
		var stadium = ''
		var matchDate = ''
		var matchHour = ''
		var finished = false
		var completedApi = false

		var pointsHome = 0
		var pointsAway = 0
		var winner = ''
		var drawnHome = ''
		var drawnAway = ''
		var loser = ''
		var fromApi = false
		var fromSessionStorage = false

		Object.values(scoresApi || {}).forEach((score) => {
			groupId = score.c?.[0]?.v
			matchNumber = parseInt(score.c?.[1]?.v)
			home = score.c?.[2]?.v
			goalsHome = parseInt(score.c?.[3]?.v)
			goalsAway = parseInt(score.c?.[4]?.v)
			away = score.c?.[5]?.v
			const normalize = (s) =>
				(s ?? '')
					.toString()
					.trim()
					.toLowerCase()
					.normalize('NFD')
					.replace(/[̀-ͯ]/g, '')
			finished = normalize(score.c?.[6]?.v) === normalize(isPlayed)
			completedApi = finished
			stadium = score.c?.[7]?.v
			matchDate = score.c?.[8]?.v
			matchHour = score.c?.[9]?.v

			// ✅ defaults seguros SIEMPRE
			matchResults = [0, 0, '', '', '', '']
			fromApi = false

			if (finished) {
				matchResults = getMatchResults(
					home,
					away,
					goalsHome,
					goalsAway,
					pointsHome,
					pointsAway,
					drawnHome,
					drawnAway,
					winner,
					loser,
				)
				fromApi = true
			}

			match = {
				groupId,
				matchNumber,
				home,
				goalsHome,
				goalsAway,
				away,
				finished,
				completedApi,
				stadium,
				matchDate,
				matchHour,
				pointsHome: matchResults[0],
				pointsAway: matchResults[1],
				winner: matchResults[4],
				loser: matchResults[5],
				drawnHome: matchResults[2],
				drawnAway: matchResults[3],
				fromApi,
				fromSessionStorage,
			}

			matches[matchNumber] = match

			winner = ''
			drawnHome = ''
			drawnAway = ''
			loser = ''
			matchResults = []
		})

		return matches
	}

	const getMatchesFromSessionStorage = () => {
		let matches = []
		let dataFromSessionStorage =
			sessionStorage.getItem(sessionStorageKey) || ''

		if (
			dataFromSessionStorage &&
			typeof dataFromSessionStorage === 'string'
		) {
			try {
				matches = JSON.parse(dataFromSessionStorage)
			} catch (err) {
				console.log(err)
			}
		}

		return matches
	}

	const matchesFromApi = getMatches(scores)
	const matchesFromSessionStorage = getMatchesFromSessionStorage()

	const restoreMatchesKeys = (matchesForKey) => {
		const entries = Object.keys(matchesForKey || {}).map((matchkey) => {
			let nMatchkey = parseInt(matchkey)
			let match = matchesForKey[nMatchkey]
			if (!match) return null
			let newKey = match.matchNumber
			return { [newKey]: match }
		})
		return Object.assign([], ...entries.filter(Boolean))
	}

	const mergeApiWithSession = (apiMatches, ssMatches) => {
		const ssByNumber = restoreMatchesKeys(ssMatches)
		const merged = []
		apiMatches.forEach((apiMatch) => {
			if (!apiMatch) return
			const n = apiMatch.matchNumber
			merged[n] = apiMatch.completedApi
				? apiMatch
				: ssByNumber[n] || apiMatch
		})
		return merged
	}

	const matches =
		matchesFromSessionStorage.length > 0
			? mergeApiWithSession(matchesFromApi, matchesFromSessionStorage)
			: matchesFromApi

	const getMatchesByGroup = (matchesParam) => {
		const source = matchesParam || matches || []
		const groupByGroupId = source.reduce((group, match) => {
			if (!match) return group
			const { groupId } = match
			if (!groupId) return group
			group[groupId] = group[groupId] ?? []
			group[groupId] = [...group[groupId], match]
			return group
		}, {})

		return groupByGroupId
	}

	const getStandingByGroup = (matchesOfGroup, teams) => {
		if (!teams) return []

		if (!matchesOfGroup?.length) {
			const base = Object.values(teams)
			base.sort((a, b) => a.name.localeCompare(b.name))
			return base
		}

		var pointsHome = 0
		var pointsAway = 0
		var playedMatches = 0
		var goalsFor = 0
		var goalsAgainst = 0
		var wonMatches = 0
		var drawnMatches = 0
		var lostMatches = 0
		var arrayTeams = []

		Object.values(teams).forEach((team) => {
			matchesOfGroup.forEach((match) => {
				if (match?.finished) {
					if (team.id === match.home) {
						pointsHome += match.pointsHome || 0
						playedMatches++
						goalsFor += match.goalsHome || 0
						goalsAgainst += match.goalsAway || 0
					}
					if (team.id === match.away) {
						pointsAway += match.pointsAway || 0
						playedMatches++
						goalsFor += match.goalsAway || 0
						goalsAgainst += match.goalsHome || 0
					}
					if (team.id === match.winner) wonMatches++
					if (team.id === match.loser) lostMatches++
					if (
						team.id === match.drawnHome ||
						team.id === match.drawnAway
					)
						drawnMatches++
				}
			})

			team.points = pointsHome + pointsAway
			team.playedMatches = playedMatches
			team.goalsFor = goalsFor
			team.goalsAgainst = goalsAgainst
			team.goalsDifference = goalsFor - goalsAgainst
			team.wonMatches = wonMatches
			team.lostMatches = lostMatches
			team.drawnMatches = drawnMatches

			pointsHome = 0
			pointsAway = 0
			playedMatches = 0
			goalsFor = 0
			goalsAgainst = 0
			wonMatches = 0
			drawnMatches = 0
			lostMatches = 0
		})

		arrayTeams = Object.values(teams)
		return rankGroupTeams(arrayTeams, matchesOfGroup)
	}

	const getAllStandings = (matchesByGroupParam) => {
		var nextStandings = {}

		Object.keys(matchesByGroupParam || {})
			.sort()
			.forEach((groupId) => {
				if (!teamsByGroup?.[groupId]) return

				const freshMatchesByGroup = getMatchesByGroup(matches)
				nextStandings[groupId] = getStandingByGroup(
					freshMatchesByGroup[groupId] || [],
					teamsByGroup[groupId],
				)
			})

		return nextStandings
	}

	const matchesByGroup = getMatchesByGroup(matches)

	useEffect(() => {
		setStandings(getAllStandings(matchesByGroup))
		setShowStandings(true)
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [scores])

	const UserPersistForm = () =>
		sessionStorage.setItem(
			sessionStorageKey,
			JSON.stringify((matches || []).filter((mch) => mch !== null)),
		)

	const updateStanding = (data) => {
		var pointsHome = 0
		var pointsAway = 0
		var winner = ''
		var drawnHome = ''
		var drawnAway = ''
		var loser = ''

		var home = ''
		var goalsHome = 0
		var goalsAway = 0
		var away = ''

		const groupId = data.group
		var matchesByGroupLocal = getMatchesByGroup(matches)
		const matchesOfGroup = matchesByGroupLocal[groupId] || []
		const matchesNumbers = matchesOfGroup.map((match) => match.matchNumber)

		matchesNumbers.forEach((matchNum) => {
			home = data[`match${matchNum}Home`]
			goalsHome = data[`match${matchNum}HomeGoals`]
			goalsAway = data[`match${matchNum}AwayGoals`]
			away = data[`match${matchNum}Away`]

			if (Number.isInteger(goalsHome) && Number.isInteger(goalsAway)) {
				matchResults = getMatchResults(
					home,
					away,
					goalsHome,
					goalsAway,
					pointsHome,
					pointsAway,
					drawnHome,
					drawnAway,
					winner,
					loser,
				)

				if (matches?.[matchNum]) {
					matches[matchNum].goalsHome = goalsHome
					matches[matchNum].goalsAway = goalsAway
					matches[matchNum].finished = true
					matches[matchNum].pointsHome = matchResults[0]
					matches[matchNum].pointsAway = matchResults[1]
					matches[matchNum].winner = matchResults[4]
					matches[matchNum].loser = matchResults[5]
					matches[matchNum].drawnHome = matchResults[2]
					matches[matchNum].drawnAway = matchResults[3]
					matches[matchNum].update = true
					matches[matchNum].fromSessionStorage = true
				}

				winner = ''
				drawnHome = ''
				drawnAway = ''
				loser = ''
				matchResults = []
			}
		})

		const newStanding = getStandingByGroup(
			matchesByGroupLocal[groupId] || [],
			teamsByGroup[groupId],
		)

		const next =
			typeof standings === 'object' && standings !== null
				? { ...standings }
				: {}
		next[groupId] = newStanding
		setStandings(next)

		getKnockoutStage(next)
		UserPersistForm()
	}

	const onSubmitFormA = (data) => updateStanding(data)
	const onSubmitFormB = (data) => updateStanding(data)
	const onSubmitFormC = (data) => updateStanding(data)
	const onSubmitFormD = (data) => updateStanding(data)
	const onSubmitFormE = (data) => updateStanding(data)
	const onSubmitFormF = (data) => updateStanding(data)
	const onSubmitFormG = (data) => updateStanding(data)
	const onSubmitFormH = (data) => updateStanding(data)
	const onSubmitFormI = (data) => updateStanding(data)
	const onSubmitFormJ = (data) => updateStanding(data)
	const onSubmitFormK = (data) => updateStanding(data)
	const onSubmitFormL = (data) => updateStanding(data)

	const formErrors = {
		A: errorsA,
		B: errorsB,
		C: errorsC,
		D: errorsD,
		E: errorsE,
		F: errorsF,
		G: errorsG,
		H: errorsH,
		I: errorsI,
		J: errorsJ,
		K: errorsK,
		L: errorsL,
	}

	const handleSubmitForms = {
		A: handleSubmitA,
		B: handleSubmitB,
		C: handleSubmitC,
		D: handleSubmitD,
		E: handleSubmitE,
		F: handleSubmitF,
		G: handleSubmitG,
		H: handleSubmitH,
		I: handleSubmitI,
		J: handleSubmitJ,
		K: handleSubmitK,
		L: handleSubmitL,
	}

	const onSubmitForms = {
		A: onSubmitFormA,
		B: onSubmitFormB,
		C: onSubmitFormC,
		D: onSubmitFormD,
		E: onSubmitFormE,
		F: onSubmitFormF,
		G: onSubmitFormG,
		H: onSubmitFormH,
		I: onSubmitFormI,
		J: onSubmitFormJ,
		K: onSubmitFormK,
		L: onSubmitFormL,
	}

	const registerForms = {
		A: registerA,
		B: registerB,
		C: registerC,
		D: registerD,
		E: registerE,
		F: registerF,
		G: registerG,
		H: registerH,
		I: registerI,
		J: registerJ,
		K: registerK,
		L: registerL,
	}

	const getKnockoutStage = (standingsParam) =>
		setKnockOutStage(
			buildRoundOf32(standingsParam || standings, { groupFinished }),
		)

	const groupsToRender = Object.keys(matchesByGroup || {})
		.sort()
		.filter((groupLetter) =>
			Boolean(
				registerForms[groupLetter] &&
				handleSubmitForms[groupLetter] &&
				teamsByGroup?.[groupLetter],
			),
		)

	const groupStageMatches = groupsToRender.flatMap(
		(groupLetter) => matchesByGroup[groupLetter] || [],
	)
	const isGroupStageFinished =
		groupsToRender.length === 12 &&
		groupStageMatches.length === 72 &&
		groupStageMatches.every((match) => match?.finished === true)

	return (
		<section>
			<section className="text-center">
				<p className="mb-0 title">{epigraph}</p>
				<p className="mt-2 title color-red">
					Recuerda que los ocho mejores terceros también clasifican a
					16avos.
				</p>
			</section>

			<section className="row my-5 px-2 px-md-0">
				{groupsToRender.map((groupLetter) => (
					<section
						key={groupLetter}
						className="col-12 col-md-6 px-1 px-md-2">
						<MatchesByGroup
							group={groupLetter}
							errors={formErrors[groupLetter]}
							handleSubmitForm={handleSubmitForms[groupLetter]}
							matches={matchesByGroup[groupLetter]}
							onSubmitForm={onSubmitForms[groupLetter]}
							register={registerForms[groupLetter]}
							teams={teamsByGroup[groupLetter]}
							urlAssets={urlFlags}
						/>

						{showStandings && (
							<StandingByGroup
								standings={standings?.[groupLetter] || []}
								urlAssets={urlFlags}
							/>
						)}
					</section>
				))}

				{isGroupStageFinished && (
						<section className="col-12 d-flex justify-content-center">
							<button
								className="btn btn-next text-white"
								style={{
									padding: '7px 16px',
									borderRadius: '17px',
									height: '33px',
									border: '1px solid #fff',
								}}
								type="button"
								onClick={() => {
									setKnockOutStage(
										buildRoundOf32(standings, { groupFinished }),
									)
									setStage(knockOutStagePos)
								}}>
								Siguiente
							</button>
						</section>
					)}
			</section>

			{/* {showStandings && ( */}
			<section className="col-12">
				<ThirdPlaceTable
					standingsByGroup={standings}
					urlAssets={urlFlags}
				/>
			</section>
			{/* )} */}
		</section>
	)
}

export default GroupStage
