import { useContext, useEffect, useState } from "react";
import axios from "axios";

import { headers, idEntityApi, responseStatusOk } from "../../Constants";

//context
import GroupsContext from "../../context/GroupsContext";

//hooks
import { useIsDesktop } from "../../hooks/useIsDesktop";

//knockout
import { buildRoundOf32 } from "../../knockout/bracket2026";

//components
import KnockOutStage from "./KnockOutStage";
import FinalForm from "./FinalForm";
import ConfirmationModal from "./ConfirmationModal";

const KnockOutStageForm = () => {
  const { groupFinished, standings, knockOutStage, setKnockOutStage } =
    useContext(GroupsContext);

  const isDesktop = useIsDesktop();
  const width = isDesktop ? "w-50" : "w-100";
  const [champion, setChampion] = useState({});

  const [showFinalForm, setShowFinalForm] = useState(false);

  const urlForm = `https://elcomercio-data.com/formulario-input?form_id=${idEntityApi}`;

  const [isSubmitted, setIsSubmitted] = useState(false);
  const [idPronostico, setIdPronostico] = useState(0);

  const onSubmit = async (data) => {
    try {
      const response = await axios.post(urlForm, data, { headers });

      if (response.status === responseStatusOk) {
        setIsSubmitted(true);
        setIdPronostico(response.data.key.id);
      }
    } catch (error) {
      console.error(`Error: ${error}`);
    }

    return isSubmitted;
  };

  useEffect(() => {
    if (knockOutStage.length === 0 && standings) {
      setKnockOutStage(buildRoundOf32(standings, { groupFinished }));
    }
  }, [groupFinished, knockOutStage.length, setKnockOutStage, standings]);

  if (isSubmitted) return <ConfirmationModal idPronostico={idPronostico} />;

  if (showFinalForm)
    return <FinalForm onSubmit={onSubmit} champion={champion} width={width} />;

  if (knockOutStage.length === 0) return null;

  return (
    <KnockOutStage
      setChampion={setChampion}
      width={width}
      onFinish={() => setShowFinalForm(true)}
    />
  );
};

export default KnockOutStageForm;
