import { useContext, useState } from 'react'
import PropTypes from 'prop-types'

import { urlAssets } from '../../Constants'

//context
import GroupsContext from '../../context/GroupsContext'

//knockout config
import {
	KNOCKOUT_INSTRUCTIONS,
	KNOCKOUT_STAGE_LABELS,
	NEXT_ROUND_MATCH_NUMBERS,
	STADIUMS,
} from '../../knockout/bracket2026'

//components
import KnockOutStageTeam from './KnockOutStageTeam'
import StageName from './StageName'

const KnockOutStage = (props) => {
	const {
		finalFormPos,
		knockOutStage,
		knockoutSchedule,
		setKnockOutStage,
		setStage,
	} = useContext(GroupsContext)
	const { setChampion, width, onFinish } = props

	const totalRounds = KNOCKOUT_STAGE_LABELS.length
	const firstRoundPos = 0

	const [currentStage, setCurrentStage] = useState(() => {
		const arr = new Array(totalRounds).fill(false)
		arr[firstRoundPos] = true
		return arr
	})
	const [stageHistory, setStageHistory] = useState([])
	const [errorMatch, setErrorMatch] = useState('')
	const [selectedTeams, setSelectedTeams] = useState({})
	const [winners, setWinners] = useState(() =>
		new Array(knockOutStage.length).fill(null),
	)

	const setSelectedTeam = (id, idTeam) =>
		setSelectedTeams((prev) => ({ ...prev, [id]: idTeam }))

	const getSelectedTeam = (id) => selectedTeams[id] || ''

	const unselectTeams = () => setSelectedTeams({})

	const addWinners = (index, id, team) => {
		errorMatch && setErrorMatch('')
		setSelectedTeam(id, `${id}-${team}`)
		const nextWinners = [...winners]
		nextWinners[index] = knockOutStage[index][team]
		setWinners(nextWinners)
	}

	const getCurrentStage = () => currentStage.findIndex((pos) => pos === true)

	const getSelected = (id, idTeam) =>
		idTeam === getSelectedTeam(id) ? 'selected' : 'unselected'

	const setPreviousStage = () => {
		const currentStagePos = getCurrentStage()

		if (currentStagePos === firstRoundPos) {
			window.location.reload()
			return
		}

		if (stageHistory.length > 0) {
			const previousState = stageHistory[stageHistory.length - 1]
			setKnockOutStage(previousState.stage)
			setWinners(new Array(previousState.stage.length).fill(null))

			const tmpCurrentStage = [...currentStage]
			tmpCurrentStage.fill(false)
			tmpCurrentStage[previousState.currentStagePos] = true
			setCurrentStage(tmpCurrentStage)

			setStageHistory(stageHistory.slice(0, -1))
			unselectTeams()
		}
	}

	const setNextStage = () => {
		const resolvedWinners = winners

		if (
			!resolvedWinners.some((item) => item === null) &&
			winners.length > 1
		) {
			const currentStagePos = getCurrentStage()
			const nextRoundMatchNumbers =
				NEXT_ROUND_MATCH_NUMBERS[currentStagePos] || []

			setStageHistory([
				...stageHistory,
				{
					stage: [...knockOutStage],
					currentStagePos,
				},
			])

			const nextStage = []
			resolvedWinners.forEach((winner, i) => {
				if (i % 2 === 0) {
					nextStage.push({
						id: Math.ceil((i + 1) / 2),
						matchNumber: nextRoundMatchNumbers[Math.floor(i / 2)],
						team1: {
							id: 1,
							slug: resolvedWinners[i].slug,
							name: resolvedWinners[i].name,
							playOff: resolvedWinners[i].playOff
								? resolvedWinners[i].playOff
								: '',
						},
						team2: {
							id: 2,
							slug: resolvedWinners[i + 1].slug,
							name: resolvedWinners[i + 1].name,
							playOff: resolvedWinners[i + 1].playOff
								? resolvedWinners[i + 1].playOff
								: '',
						},
					})
				}
			})
			setKnockOutStage(nextStage)

			const tmpCurrentStage = [...currentStage]
			tmpCurrentStage.fill(false)
			tmpCurrentStage[currentStagePos + 1] = true

			setCurrentStage(tmpCurrentStage)
			setWinners(new Array(winners.length / 2).fill(null))
			unselectTeams()
		} else if (winners.length === 1 && resolvedWinners[0]) {
			setChampion(resolvedWinners[0])
			if (onFinish) onFinish(resolvedWinners[0])
			else setStage(finalFormPos)
		} else {
			setErrorMatch('Debes elegir un ganador por cada partido.')
		}
	}

	const currentRound = getCurrentStage()
	const venuesForRound = STADIUMS?.[currentRound] || []
	const getVenue = (match, index) => {
		const venue = knockoutSchedule?.[match.matchNumber]
		const text = venue
			? [venue.stadium, venue.date, venue.hour]
					.filter(Boolean)
					.join(' · ')
			: ''
		return {
			text,
			html: text ? '' : venuesForRound[index],
		}
	}

	return (
		<section style={{ marginBottom: '25px' }}>
			<section className="text-center">
				<p
					className="mb-0 px-3 px-md-0 team-name"
					style={{ color: '#05337A' }}>
					Dale click a{KNOCKOUT_INSTRUCTIONS[currentRound]}
				</p>
			</section>
			<section
				className={`d-flex justify-content-center flex-wrap ${width} mx-auto my-1 my-md-3`}>
				<article className="knockout-stage-tabs d-flex justify-content-center flex-wrap my-1 text-center">
					{KNOCKOUT_STAGE_LABELS.map((label, i) => (
						<StageName
							key={label}
							activeClass={currentStage[i]}
							stageName={label}
						/>
					))}
				</article>
			</section>
			<section
				className={`row mt-4 justify-content-between px-0 mx-auto ${width}`}
				style={{ alignItems: 'center' }}>
				{knockOutStage.map((match, i) => {
					const venue = getVenue(match, i)
					return (
						<div
							className="btn-group"
							style={{
								width: '100%',
								display: 'flex',
								flexDirection: 'column',
							}}
							key={match.id}>
							<div
								className="btn-group knockout-match-row"
								role="group"
								aria-label={`Match ${match.id}`}
								style={{
									height: '33px',
									alignItems: 'center',
									width: '100%',
									justifyContent: 'center',
								}}>
								<KnockOutStageTeam
									addWinner={addWinners}
									buttonClass={`w-100 btn d-flex justify-content-start align-items-center p-1 p-md-2 knockout-stage-${getSelected(
										match.id,
										`${match.id}-team1`,
									)}-team`}
									id={match.id}
									image={`${urlAssets}/img/${getSelected(
										match.id,
										`${match.id}-team1`,
									)}.webp`}
									index={i}
									name={match.team1.name}
									sectionClass="ps-0 pe-1"
									slug={
										!match.team1.playOff
											? match.team1.slug
											: 'repesca'
									}
									team="team1"
									textColor={`text-${getSelected(match.id, `${match.id}-team1`)}`}
									urlAssets={urlAssets}
								/>
								<p
									className="knockout-vs"
									style={{
										color: '#05337A',
										font: '500 12px/18px "Noto Sans KR"',
									}}>
									VS.
								</p>
								<KnockOutStageTeam
									addWinner={addWinners}
									buttonClass={`w-100 btn d-flex justify-content-start align-items-center p-1 p-md-2 knockout-stage-${getSelected(
										match.id,
										`${match.id}-team2`,
									)}-team`}
									id={match.id}
									image={`${urlAssets}/img/${getSelected(
										match.id,
										`${match.id}-team2`,
									)}.webp`}
									index={i}
									name={match.team2.name}
									sectionClass="ps-1 pe-0"
									slug={
										!match.team2.playOff
											? match.team2.slug
											: 'repesca'
									}
									team="team2"
									textColor={`text-${getSelected(match.id, `${match.id}-team2`)}`}
									urlAssets={urlAssets}
								/>
							</div>
							{venue.text && (
								<div
									style={{
										font: '500 9px / 13px "Noto Sans KR"',
										color: '#7E7E7E',
										margin: 'auto',
										marginTop: '5px',
										textAlign: 'center',
									}}>
									{venue.text}
								</div>
							)}
							{venue.html && (
								<div
									style={{
										font: '500 9px / 13px "Noto Sans KR"',
										color: '#7E7E7E',
										margin: 'auto',
										marginTop: '5px',
									}}
									dangerouslySetInnerHTML={{
										__html: venue.html,
									}}
								/>
							)}
						</div>
					)
				})}
				{errorMatch && (
					<section className="col-12 mt-2 text-center">
						<span className="text-danger team-name">
							{errorMatch}
						</span>
					</section>
				)}
				<section className="col-12 d-flex justify-content-center my-4">
					<button
						className="btn btn-next me-2"
						type="button"
						onClick={setPreviousStage}
						style={{
							padding: '7px 16px',
							borderRadius: '17px',
							height: '33px',
							border: '1px solid #fff',
							color: '#fff',
							backgroundColor: '#fb0000',
						}}>
						Anterior
					</button>
					<button
						className="btn btn-next text-white"
						type="button"
						onClick={setNextStage}
						style={{
							padding: '7px 16px',
							borderRadius: '17px',
							height: '33px',
							border: '1px solid #fff',
						}}>
						Siguiente
					</button>
				</section>
			</section>
		</section>
	)
}

export default KnockOutStage

KnockOutStage.propTypes = {
	setChampion: PropTypes.func.isRequired,
	width: PropTypes.string.isRequired,
	onFinish: PropTypes.func,
}
