import { useContext } from 'react'

//context
import GroupsContext from '../../context/GroupsContext'

//components
import Loading from '../common/Loading'
import Heading from '../common/Heading'
import GroupStage from '../groupStage/GroupStage'
import KnockOutStageForm from '../knockOutStage/KnockOutStageForm'
import CreditsEC from '../common/CreditsEC'

const Home = () => {
	const { loading, stage, groupStagePos, groupStageComplete } =
		useContext(GroupsContext)
	const shouldShowGroupStage = stage === groupStagePos && !groupStageComplete

	return (
		<>
			{loading ? (
				<Loading />
			) : (
				<>
					{stage !== 2 && <Heading />}
					{shouldShowGroupStage ? (
						<GroupStage />
					) : (
						<KnockOutStageForm />
					)}
				</>
			)}

			<CreditsEC />
		</>
	)
}

export default Home
