import { memo, useState, useEffect } from 'react'

import { titleHome, urlAssets } from '../../Constants'
import { useIsDesktop } from '../../hooks/useIsDesktop'

const buildSrc = (variant) => `${urlAssets}/img/header-${variant}.webp`

const Heading = () => {
	const isDesktop = useIsDesktop()
	const variant = isDesktop ? 'desktop' : 'mobile'
	const primarySrc = buildSrc(variant)
	const fallbackSrc = buildSrc(isDesktop ? 'mobile' : 'desktop')

	const [src, setSrc] = useState(primarySrc)

	useEffect(() => {
		setSrc(primarySrc)
	}, [primarySrc])

	const handleError = () => {
		setSrc((current) => (current === fallbackSrc ? current : fallbackSrc))
	}

	return (
		<section className="text-center">
			<img
				alt={titleHome}
				className="d-block img-fluid m-auto"
				src={src}
				onError={handleError}
				loading="lazy"
				decoding="async"
			/>
		</section>
	)
}

export default memo(Heading)
