// Stored in bracket-tree order, so pairing adjacent winners reproduces the
// FIFA path to quarter-finals/semi-finals. This is not chronological order.
export const BRACKET_ORDER = [
	74, 77, 73, 75, 83, 84, 81, 82, 76, 78, 79, 80, 86, 88, 85, 87,
]

