export const STADIUMS = [[], [], [], [], []]

const GROUP_LETTERS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J', 'K', 'L']

export const compareThirds = compareThirdPlaceTeams

const placeholderTeam = (label) => ({
	name: label,
	slug: '',
	playOff: '',
	pending: true,
})

export const bestThirdsCombo = (standings) => {
	const st = standings || {}
	const thirds = GROUP_LETTERS.map((g) => {
		const t = st[g]?.[2]
		return t ? { ...t, __group: g } : null
	}).filter(Boolean)

	if (thirds.length < 8) return ''

	return [...thirds]
		.sort(compareThirds)
		.slice(0, 8)
		.map((t) => t.__group)
		.sort()
		.join('')
}

export const buildRoundOf32 = (standings, options = {}) => {
	const st = standings || {}
	const { groupFinished } = options

	const groupDecided = (g) => !groupFinished || groupFinished[g]
	const thirdsResolved =
		options.thirdsResolved !== undefined
			? options.thirdsResolved
			: !groupFinished || GROUP_LETTERS.every((g) => groupFinished[g])

	const comboKey = thirdsResolved ? bestThirdsCombo(st) : ''
	const assignment = comboKey ? thirdsAssignment(comboKey) : null

	const resolve = (spec, homeWinnerGroup) => {
		if (spec.t === 'W') {
			return groupDecided(spec.g) && st[spec.g]?.[0]
				? st[spec.g][0]
				: placeholderTeam(`Ganador ${spec.g}`)
		}
		if (spec.t === 'R') {
			return groupDecided(spec.g) && st[spec.g]?.[1]
				? st[spec.g][1]
				: placeholderTeam(`2.º ${spec.g}`)
		}

		const thirdGroup = assignment?.[`1${homeWinnerGroup}`]
		return (thirdGroup && st[thirdGroup]?.[2]) || placeholderTeam('Mejor 3.º')
	}

	return BRACKET_ORDER.map((num, i) => {
		const spec = R32_MATCHES[num]
		const homeWinnerGroup = spec.home.t === 'W' ? spec.home.g : null
		return {
			id: i + 1,
			matchNumber: num,
			team1: resolve(spec.home, homeWinnerGroup),
			team2: resolve(spec.away, homeWinnerGroup),
		}
	})
}
