import { useState, useEffect, useRef } from 'react'
import axios from 'axios'

import { googleSheetKey, query, responseStatusOk } from '../Constants'

const SCORES_CACHE_KEY = 'elcomercioMundial2026_scoresCache'
const REQUEST_TIMEOUT_MS = 8000
const MAX_RETRIES = 3
const RETRY_BASE_MS = 800
const POLL_MS = 60000

const CDN_SCORES_URL = process.env.REACT_APP_SCORES_URL || ''

const buildGvizUrl = () =>
	`https://docs.google.com/spreadsheets/d/${googleSheetKey}/gviz/tq?tq=${encodeURIComponent(
		query,
	)}`

const parseGviz = (raw) => {
	if (typeof raw !== 'string') return raw
	const open = raw.indexOf('setResponse(')
	if (open === -1) throw new Error('Respuesta gviz inesperada')
	const jsonStr = raw.substring(
		open + 'setResponse('.length,
		raw.lastIndexOf(')'),
	)
	return JSON.parse(jsonStr)
}

const extractRows = (parsed) => {
	const rows = parsed?.table?.rows
	if (!Array.isArray(rows))
		throw new Error('Respuesta sin filas (table.rows)')
	return rows
}

const readCache = () => {
	try {
		const cached = localStorage.getItem(SCORES_CACHE_KEY)
		if (!cached) return null
		const parsed = JSON.parse(cached)
		return Array.isArray(parsed?.rows) ? parsed.rows : null
	} catch (e) {
		return null
	}
}

const writeCache = (rows) => {
	try {
		localStorage.setItem(
			SCORES_CACHE_KEY,
			JSON.stringify({ rows, savedAt: Date.now() }),
		)
	} catch (e) {}
}

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms))

const SIMULATE_FINISHED = process.env.REACT_APP_SIMULATE_FINISHED === 'true'
const simulateAllFinished = (rows) =>
	(rows || []).map((row, i) => {
		const c = (row.c || []).map((cell) => (cell ? { ...cell } : cell))
		if (c[3] == null || c[3].v == null) c[3] = { v: i % 4 }
		if (c[4] == null || c[4].v == null) c[4] = { v: (i + 1) % 3 }
		c[6] = { v: 'Sí' }
		return { ...row, c }
	})

const useScores = () => {
	const [loading, setLoading] = useState(true)
	const [scores, setScores] = useState([])
	const mounted = useRef(true)

	useEffect(() => {
		mounted.current = true

		const fetchRows = async () => {
			const useCdn = Boolean(CDN_SCORES_URL)
			const url = useCdn ? CDN_SCORES_URL : buildGvizUrl()

			for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
				try {
					const result = await axios.get(url, {
						timeout: REQUEST_TIMEOUT_MS,
						params: useCdn ? undefined : { _: Date.now() },
					})
					if (result.status !== responseStatusOk) {
						throw new Error(`HTTP ${result.status}`)
					}
					return extractRows(parseGviz(result.data))
				} catch (error) {
					const isLast = attempt === MAX_RETRIES - 1
					console.log(
						`Intento ${attempt + 1}/${MAX_RETRIES} falló: ${error}`,
					)
					if (!isLast) {
						await sleep(RETRY_BASE_MS * 2 ** attempt)
					}
				}
			}
			return null
		}

		const load = async (isInitial) => {
			const rows = await fetchRows()
			if (!mounted.current) return

			if (rows) {
				setScores(SIMULATE_FINISHED ? simulateAllFinished(rows) : rows)
				writeCache(rows)
			} else if (isInitial) {
				const cached = readCache()
				if (cached) setScores(cached)
			}

			if (isInitial) setLoading(false)
		}

		load(true)
		const intervalId = setInterval(() => load(false), POLL_MS)

		return () => {
			mounted.current = false
			clearInterval(intervalId)
		}
	}, [])

	return [loading, scores]
}

export { useScores }
