import { memo, useEffect } from "react";
import PropTypes from "prop-types";
import confetti from "canvas-confetti";

import { urlAssets } from "../../Constants";

const CONFETTI_COLORS = ["#fb0000", "#05337a", "#ffd700", "#ffffff"];
const CELEBRATION_MS = 3500;

const Champion = (props) => {
  const { name, slugFlag } = props;

  useEffect(() => {
    const timers = [];
    const end = Date.now() + CELEBRATION_MS;

    // Ráfaga inicial desde ambos lados
    const fireBurst = () => {
      [
        { x: 0, angle: 60 },
        { x: 1, angle: 120 },
      ].forEach(({ x, angle }) =>
        confetti({
          particleCount: 90,
          spread: 75,
          angle,
          origin: { x, y: 0.65 },
          colors: CONFETTI_COLORS,
          disableForReducedMotion: true,
        })
      );
    };

    // Lluvia continua hasta agotar el tiempo de celebración
    const fireRain = () => {
      confetti({
        particleCount: 4,
        startVelocity: 0,
        ticks: 220,
        gravity: 0.65,
        spread: 360,
        scalar: 0.9,
        origin: { x: Math.random(), y: -0.1 },
        colors: CONFETTI_COLORS,
        disableForReducedMotion: true,
      });
      if (Date.now() < end) {
        timers.push(setTimeout(fireRain, 220));
      }
    };

    fireBurst();
    timers.push(setTimeout(fireRain, 250));

    return () => {
      timers.forEach(clearTimeout);
      confetti.reset();
    };
  }, []);

  return (
    <section className="champion-celebration text-center mb-3">
      {slugFlag ? (
        <img
          className="champion-flag"
          src={`${urlAssets}/img/flags/${slugFlag}.png`}
          alt={name || "Selección campeona"}
          loading="lazy"
        />
      ) : (
        <span className="champion-flag champion-flag--placeholder" aria-hidden="true" />
      )}
      {name && <p className="champion-name mb-1">{name}</p>}
      <p className="champion-subtitle mb-0">
        Según tu pronóstico, levanta la Copa del Mundo 2026 🏆
      </p>
    </section>
  );
};

export default memo(Champion);

Champion.propTypes = {
  name: PropTypes.string,
  slugFlag: PropTypes.string,
};

Champion.defaultProps = {
  name: "",
  slugFlag: "",
};
