import { isPlayed } from './Constants'
import { teamsByGroup } from './teams/TeamsByGroup'

const GROUP_LETTERS = ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H', 'I', 'J', 'K', 'L']
const MATCHES_PER_GROUP = 6

const normalize = (s) =>
	(s ?? '')
		.toString()
		.trim()
		.toLowerCase()
		.normalize('NFD')
		.replace(/[\u0300-\u036f]/g, '')

const isFinishedCell = (cell) => normalize(cell) === normalize(isPlayed)

const toNumber = (value, fallback = 0) => {
	const n = Number(value)
	return Number.isFinite(n) ? n : fallback
}

const hasScore = (goalsHome, goalsAway) =>
	Number.isFinite(goalsHome) && Number.isFinite(goalsAway)

const getTeamKey = (team) => team.id || team.name

const compareNumberDesc = (a, b, prop) => {
	if (a[prop] !== b[prop]) return b[prop] - a[prop]
	return 0
}

const teamConductScore = (team) =>
	toNumber(team.fairPlayPoints ?? team.conductScore, 0)

const teamFifaRank = (team) =>
	Number.isFinite(Number(team.fifaRank))
		? Number(team.fifaRank)
		: Number.MAX_SAFE_INTEGER

const compareAvailableFifaFallbacks = (a, b) => {
	const gd = compareNumberDesc(a, b, 'goalsDifference')
	if (gd) return gd
	const gf = compareNumberDesc(a, b, 'goalsFor')
	if (gf) return gf

	const conduct = teamConductScore(b) - teamConductScore(a)
	if (conduct) return conduct

	const rank = teamFifaRank(a) - teamFifaRank(b)
	if (rank) return rank

	return 0
}

const makeHeadToHeadStats = (teams, matches) => {
	const ids = new Set(teams.map(getTeamKey))
	const stats = {}

	teams.forEach((team) => {
		stats[getTeamKey(team)] = {
			points: 0,
			goalsFor: 0,
			goalsAgainst: 0,
			goalsDifference: 0,
		}
	})

	;(matches || []).forEach((match) => {
		if (!match?.finished) return
		if (!ids.has(match.home) || !ids.has(match.away)) return

		const goalsHome = toNumber(match.goalsHome)
		const goalsAway = toNumber(match.goalsAway)
		const home = stats[match.home]
		const away = stats[match.away]
		if (!home || !away) return

		home.goalsFor += goalsHome
		home.goalsAgainst += goalsAway
		away.goalsFor += goalsAway
		away.goalsAgainst += goalsHome

		if (goalsHome > goalsAway) home.points += 3
		else if (goalsAway > goalsHome) away.points += 3
		else {
			home.points += 1
			away.points += 1
		}
	})

	Object.values(stats).forEach((teamStats) => {
		teamStats.goalsDifference =
			teamStats.goalsFor - teamStats.goalsAgainst
	})

	return stats
}

const compareHeadToHeadStats = (stats, a, b) => {
	const aStats = stats[getTeamKey(a)]
	const bStats = stats[getTeamKey(b)]

	const points = compareNumberDesc(aStats, bStats, 'points')
	if (points) return points
	const gd = compareNumberDesc(aStats, bStats, 'goalsDifference')
	if (gd) return gd
	return compareNumberDesc(aStats, bStats, 'goalsFor')
}

const headToHeadKey = (stats, team) => {
	const teamStats = stats[getTeamKey(team)]
	return [
		teamStats.points,
		teamStats.goalsDifference,
		teamStats.goalsFor,
	].join('|')
}

const bucketByEqualHeadToHead = (teams, stats) => {
	const buckets = []
	teams.forEach((team) => {
		const key = headToHeadKey(stats, team)
		const lastBucket = buckets[buckets.length - 1]
		if (lastBucket?.key === key) lastBucket.teams.push(team)
		else buckets.push({ key, teams: [team] })
	})
	return buckets
}

const rankHeadToHead = (teams, matches) => {
	if (teams.length <= 1) return teams

	const stats = makeHeadToHeadStats(teams, matches)
	const sorted = [...teams].sort((a, b) =>
		compareHeadToHeadStats(stats, a, b),
	)
	const buckets = bucketByEqualHeadToHead(sorted, stats)
	if (buckets.length === 1) return null

	return buckets.flatMap((bucket) => {
		if (bucket.teams.length === 1) return bucket.teams
		return (
			rankHeadToHead(bucket.teams, matches) ||
			[...bucket.teams].sort(compareAvailableFifaFallbacks)
		)
	})
}

const bucketByPoints = (teams) => {
	const sorted = [...teams].sort((a, b) => b.points - a.points)
	const buckets = []
	sorted.forEach((team) => {
		const lastBucket = buckets[buckets.length - 1]
		if (lastBucket?.points === team.points) lastBucket.teams.push(team)
		else buckets.push({ points: team.points, teams: [team] })
	})
	return buckets
}

export const rankGroupTeams = (teams, matches = []) =>
	bucketByPoints(teams).flatMap((bucket) => {
		if (bucket.teams.length === 1) return bucket.teams
		return (
			rankHeadToHead(bucket.teams, matches) ||
			[...bucket.teams].sort(compareAvailableFifaFallbacks)
		)
	})

export const compareThirdPlaceTeams = (a, b) => {
	const points = compareNumberDesc(a, b, 'points')
	if (points) return points
	return compareAvailableFifaFallbacks(a, b)
}

const freshTeam = (t) => ({
	...t,
	points: 0,
	playedMatches: 0,
	wonMatches: 0,
	drawnMatches: 0,
	lostMatches: 0,
	goalsFor: 0,
	goalsAgainst: 0,
	goalsDifference: 0,
})

export const computeStandings = (scores, options = {}) => {
	const matchesByGroup = {}
	Object.values(scores || {}).forEach((score) => {
		const groupId = score?.c?.[0]?.v
		if (!groupId || !teamsByGroup[groupId]) return
		const goalsHome = parseInt(score.c?.[3]?.v, 10)
		const goalsAway = parseInt(score.c?.[4]?.v, 10)
		matchesByGroup[groupId] = matchesByGroup[groupId] || []
		matchesByGroup[groupId].push({
			home: score.c?.[2]?.v,
			away: score.c?.[5]?.v,
			goalsHome,
			goalsAway,
			finished:
				isFinishedCell(score.c?.[6]?.v) ||
				(options.inferFinishedFromScores && hasScore(goalsHome, goalsAway)),
		})
	})

	const standings = {}
	const groupFinished = {}

	GROUP_LETTERS.forEach((g) => {
		if (!teamsByGroup[g]) return
		const teams = {}
		Object.values(teamsByGroup[g]).forEach((t) => {
			teams[t.id] = freshTeam(t)
		})

		const ms = matchesByGroup[g] || []
		ms.forEach((m) => {
			if (!m.finished) return
			const home = teams[m.home]
			const away = teams[m.away]
			if (!home || !away) return
			const gh = Number.isFinite(m.goalsHome) ? m.goalsHome : 0
			const ga = Number.isFinite(m.goalsAway) ? m.goalsAway : 0
			home.playedMatches++
			away.playedMatches++
			home.goalsFor += gh
			home.goalsAgainst += ga
			away.goalsFor += ga
			away.goalsAgainst += gh
			if (gh > ga) {
				home.points += 3
				home.wonMatches++
				away.lostMatches++
			} else if (ga > gh) {
				away.points += 3
				away.wonMatches++
				home.lostMatches++
			} else {
				home.points++
				away.points++
				home.drawnMatches++
				away.drawnMatches++
			}
		})

		Object.values(teams).forEach((t) => {
			t.goalsDifference = t.goalsFor - t.goalsAgainst
		})

		standings[g] = rankGroupTeams(Object.values(teams), ms)
		groupFinished[g] =
			ms.length === MATCHES_PER_GROUP && ms.every((m) => m.finished)
	})

	const groupStageComplete = GROUP_LETTERS.every((g) => groupFinished[g])

	return { standings, groupFinished, groupStageComplete }
}

export const computeKnockoutSchedule = (scores) => {
	const schedule = {}
	Object.values(scores || {}).forEach((score) => {
		const matchNumber = parseInt(score?.c?.[1]?.v, 10)
		if (!Number.isFinite(matchNumber) || matchNumber < 73) return
		schedule[matchNumber] = {
			stadium: score.c?.[7]?.v || '',
			date: score.c?.[8]?.f || score.c?.[8]?.v || '',
			hour: score.c?.[9]?.v || '',
		}
	})
	return schedule
}
